#=================================================
# LISTA DESPLEGABLE
#=================================================

opciones = {

f"{nombre} ({matricula})":matricula

for matricula,nombre in alumnos.items()

}


seleccion = st.selectbox(

    "Seleccione su nombre",

    [""] + list(opciones.keys())

)


if seleccion != "":

    matricula = opciones[seleccion]

    nombre = alumnos[matricula]

    st.success(nombre)

    st.info(f"Matrícula: {matricula}")


    st.subheader("Firme en el recuadro")


    canvas_result = st_canvas(

        stroke_width=3,

        stroke_color="#0A3CAA",

        background_color="#FFFFFF",

        width=500,

        height=150,

        drawing_mode="freedraw",

        key="firma"

    )


    if st.button("Guardar firma"):


        if canvas_result.image_data is not None:


            img = Image.fromarray(

                canvas_result.image_data[:,:,:3]

                .astype(np.uint8)

            )


            archivo_png = f"firmas/{matricula}.png"


            img.save(

                archivo_png

            )


            st.success(

                "Firma guardada"

            )


            #======================================
            # ABRIR PDF FIRMADO
            #======================================


            pdf = fitz.open(

                PDF_FIRMADO

            )


            encontrado = False


            for i in range(

                len(pdf)

            ):


                pagina = pdf[i]


                # Buscar matrícula

                resultados = pagina.search_for(

                    matricula

                )


                if len(resultados)>0:


                    r = resultados[0]


                    #--------------------------------

                    # A la derecha del nombre

                    #--------------------------------


                    x1 = r.x1 + 420

                    y1 = r.y0 - 5

                    x2 = x1 + 55

                    y2 = y1 + 20


                    rect = fitz.Rect(

                        x1,

                        y1,

                        x2,

                        y2

                    )


                    # DIBUJAR RECTÁNGULO ROJO

#                    pagina.draw_rect(

#                        rect,

#                        color=(1,0,0),

#                        width=1

#                    )


                    pagina.insert_image(

                        rect,

                        filename=archivo_png,

                        keep_proportion=True

                    )


                    encontrado = True


                    break



            if encontrado:


                pdf.save(

                    PDF_FIRMADO,

                    incremental=True,

                    encryption=0

                )


                pdf.close()


                st.success(

                    "✅ Firma agregada al PDF"

                )


